// This program implements a sorting algorithm that can be evolved to adapt to different data patterns

use std::cmp::Ordering;

// EVOLVE-BLOCK-START
pub fn adaptive_sort<T: Ord + Clone>(arr: &mut [T]) {
    let n = arr.len();
    if n < 2 { return; }

    // Check for sorted/reverse sorted arrays (O(N) adaptability optimization)
    if arr.windows(2).all(|w| w[0] <= w[1]) { return; }
    if arr.windows(2).all(|w| w[0] >= w[1]) { arr.reverse(); return; }

    quicksort(arr);
}

fn quicksort<T: Ord + Clone>(mut arr: &mut [T]) {
    loop {
        let len = arr.len();
        if len < 20 {
            for i in 1..len {
                let mut j = i;
                while j > 0 && arr[j - 1] > arr[j] {
                    arr.swap(j, j - 1);
                    j -= 1;
                }
            }
            return;
        }

        let mid = len / 2;
        if arr[mid] < arr[0] { arr.swap(0, mid); }
        if arr[len - 1] < arr[0] { arr.swap(0, len - 1); }
        if arr[len - 1] < arr[mid] { arr.swap(mid, len - 1); }

        let pivot = arr[mid].clone();
        let (mut l, mut i, mut r) = (0, 0, len);

        while i < r {
            match arr[i].cmp(&pivot) {
                Ordering::Less => {
                    arr.swap(i, l);
                    i += 1;
                    l += 1;
                }
                Ordering::Greater => {
                    r -= 1;
                    arr.swap(i, r);
                }
                Ordering::Equal => {
                    i += 1;
                }
            }
        }

        // Tail recursion optimization: sort smaller partition recursively, loop for larger
        if l < len - r {
            quicksort(&mut arr[..l]);
            arr = &mut arr[r..];
        } else {
            quicksort(&mut arr[r..]);
            arr = &mut arr[..l];
        }
    }
}
// EVOLVE-BLOCK-END

// Benchmark function to test the sort implementation
pub fn run_benchmark(test_data: Vec<Vec<i32>>) -> BenchmarkResults {
    let mut results = BenchmarkResults {
        times: Vec::new(),
        correctness: Vec::new(),
        adaptability_score: 0.0,
    };

    for data in test_data {
        let mut arr = data.clone();
        let start = std::time::Instant::now();

        adaptive_sort(&mut arr);

        let elapsed = start.elapsed();
        results.times.push(elapsed.as_secs_f64());

        // Check if correctly sorted
        let is_sorted = arr.windows(2).all(|w| w[0] <= w[1]);
        results.correctness.push(is_sorted);
    }

